import React, { useEffect, useState } from "react";
import { useParams, Link } from "react-router-dom";
import axios from "axios";
import "../styles/roomdetails.css";

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8000";

export default function RoomDetails() {
  const { id } = useParams();

  const [room, setRoom] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [selectedImage, setSelectedImage] = useState(null);

  /* ================= FETCH ROOM ================= */
  useEffect(() => {
    if (!id) {
      setError("Invalid room");
      setLoading(false);
      return;
    }

    axios
      .get(`${API_BASE}/api/rooms/${id}/`)
      .then((res) => {
        setRoom(res.data);
      })
      .catch(() => {
        setError("Room not found");
      })
      .finally(() => {
        setLoading(false);
      });
  }, [id]);

  /* ================= SCROLL ANIMATIONS ================= */
  useEffect(() => {
    if (loading) return;

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add("show");
            observer.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.1 }
    );

    document
      .querySelectorAll(
        ".fade-in, .fade-up, .fade-left, .fade-right, .amenity, .spec-card, .gallery-item"
      )
      .forEach((el) => observer.observe(el));

    return () => observer.disconnect();
  }, [loading]);

  /* ================= STATES ================= */
  if (loading) return <p style={{ padding: 40 }}>Loading...</p>;
  if (error) return <p style={{ padding: 40 }}>{error}</p>;
  if (!room) return null;

  /* ================= HERO IMAGES ================= */
  const roomImages = Array.isArray(room.images) && room.images.length > 0
    ? room.images.map((img) =>
        img.image.startsWith("http")
          ? img.image
          : `${API_BASE}${img.image}`
      )
    : [];

  const heroImage = roomImages[0] || "";

  return (
    <>
      {/* ================= NAV ================= */}
      <header className="nav fade-in">
        <div className="nav-inner">
          <img
            src="/assets/images/glamp_logo.png"
            alt="The Paradise Glamp"
            className="logo"
          />
          <nav className="menu">
            <Link to="/">Home</Link>
            <Link to="/reservation">Reservation</Link>
            <Link className="reserve" to="/reservation">
              Reserve
            </Link>
          </nav>
        </div>
      </header>

      {/* ================= HERO ================= */}
      <section
        className="hero fade-up"
        style={{
          background: heroImage
            ? `url("${heroImage}") center/cover no-repeat`
            : "#000",
        }}
      >
        <div className="hero-overlay">
          <div className="hero-wrap">
            <div className="arch">
              <div className="arch-inner">
                <div className="stars-row">★★★★★</div>
                <h1>{room.room_name}</h1>
                <p className="lead">
                  Experience nature with unmatched comfort & elegance
                </p>
                <div className="breadcrumb">
                  <Link to="/">Home</Link> / Room Details
                </div>
              </div>
            </div>
          </div>
        </div>
        <div className="hero-gradient"></div>
      </section>

      {/* ================= ROOM DETAILS ================= */}
      <section className="room-details">
        <div className="room-container">
          {/* ================= ARCH GALLERY ================= */}
          {roomImages.length > 0 && (
            <div className="gallery-section fade-up">
              <div className="main-image" onClick={() => setSelectedImage(0)}>
                <img src={roomImages[0]} alt={room.room_name} />
                <div className="overlay">
                  <span>View Gallery</span>
                </div>
              </div>
              {roomImages.length > 1 && (
                <div className="thumbnail-grid">
                  {roomImages.slice(1, 5).map((img, idx) => (
                    <div 
                      key={idx} 
                      className="thumbnail-item"
                      onClick={() => setSelectedImage(idx + 1)}
                    >
                      <img src={img} alt={`${room.room_name} ${idx + 2}`} />
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* ================= ROOM CONTENT ================= */}
          <div className="room-content-grid">
            <div className="room-main">
              <div className="section-header fade-up">
                <span className="subtitle">LUXURY ACCOMMODATION</span>
                <h2>{room.room_name}</h2>
                <div className="divider"></div>
              </div>

              <p className="room-description fade-left">
                {room.description}
              </p>

              {/* ================= AMENITIES ================= */}
              <div className="amenities-section fade-up">
                <h3>Room Amenities</h3>
                <div className="amenities-grid">
                  {[
                    ["fa-wifi", "Free WiFi"],
                    ["fa-tv", "Smart TV"],
                    ["fa-snowflake", "Air Conditioning"],
                    ["fa-shower", "Rain Shower"],
                    ["fa-bath", "Bathtub"],
                    ["fa-coffee", "Coffee Maker"],
                    ["fa-utensils", "Dining Area"],
                    ["fa-safe", "Safe Box"],
                    ["fa-mountain", "Mountain View"],
                    ["fa-parking", "Free Parking"],
                  ].map(([icon, text], idx) => (
                    <div 
                      className="amenity-item" 
                      key={text}
                      style={{ animationDelay: `${idx * 0.05}s` }}
                    >
                      <i className={`fas ${icon}`}></i>
                      <span>{text}</span>
                    </div>
                  ))}
                </div>
              </div>

              {/* ================= POLICIES ================= */}
              <div className="policies-section fade-up">
                <div className="policy-box">
                  <i className="fas fa-clock"></i>
                  <div>
                    <h4>Check-in</h4>
                    <p>From 2:00 PM</p>
                  </div>
                </div>
                <div className="policy-box">
                  <i className="fas fa-sign-out-alt"></i>
                  <div>
                    <h4>Check-out</h4>
                    <p>Until 11:00 AM</p>
                  </div>
                </div>
                <div className="policy-box">
                  <i className="fas fa-ban"></i>
                  <div>
                    <h4>Cancellation</h4>
                    <p>Free until 24h before</p>
                  </div>
                </div>
              </div>
            </div>

            {/* ================= BOOKING CARD ================= */}
            <div className="booking-sidebar fade-right">
              <div className="booking-card">
                <div className="price-section">
                  <span className="price-label">Starting from</span>
                  <div className="price-display">
                    <span className="currency">₹</span>
                    <span className="amount">{Number(room.price).toLocaleString()}</span>
                    <span className="period">/ night</span>
                  </div>
                </div>
                
                <div className="availability">
                  <i className="fas fa-check-circle"></i>
                  <span>Available for booking</span>
                </div>

                <Link to="/reservation" className="reserve-btn">
                  RESERVE NOW
                </Link>

                <div className="booking-features">
                  <div className="feature">
                    <i className="fas fa-check"></i>
                    <span>Free Cancellation</span>
                  </div>
                  <div className="feature">
                    <i className="fas fa-check"></i>
                    <span>Breakfast Included</span>
                  </div>
                  <div className="feature">
                    <i className="fas fa-check"></i>
                    <span>Best Price Guarantee</span>
                  </div>
                </div>

                <div className="contact-box">
                  <p>Need help?</p>
                  <a href="tel:+919497185771">+91 9497185771</a>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* ================= LIGHTBOX ================= */}
      {selectedImage !== null && roomImages.length > 0 && (
        <div className="lightbox" onClick={() => setSelectedImage(null)}>
          <button className="lightbox-close">
            <i className="fas fa-times"></i>
          </button>
          <button 
            className="lightbox-nav prev"
            onClick={(e) => {
              e.stopPropagation();
              setSelectedImage((selectedImage - 1 + roomImages.length) % roomImages.length);
            }}
          >
            <i className="fas fa-chevron-left"></i>
          </button>
          <img 
            src={roomImages[selectedImage]} 
            alt={room.room_name} 
            onClick={(e) => e.stopPropagation()}
          />
          <button 
            className="lightbox-nav next"
            onClick={(e) => {
              e.stopPropagation();
              setSelectedImage((selectedImage + 1) % roomImages.length);
            }}
          >
            <i className="fas fa-chevron-right"></i>
          </button>
          <div className="lightbox-counter">
            {selectedImage + 1} / {roomImages.length}
          </div>
        </div>
      )}

      {/* ================= FOOTER ================= */}
      <footer className="footer fade-in">
        <div className="footer-inner">
          <div>
            <h4>Address</h4>
            <p>Adimali, Idukki, Kerala</p>
          </div>
          <div>
            <h4>Contact</h4>
            <p>+91 9497185771</p>
            <p>theparadiseglamp@gmail.com</p>
          </div>
        </div>
      </footer>
    </>
  );
}
